  {
    "key": "KAN-4",
    "fields": {
      "summary": "Build Senior Developer agent (spec-driven, human-in-the-loop)",
      "description": {
        "content": [
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Description",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "text": "Create the Senior Developer agent: a workflow for complex tickets that produces a spec artifact and pauses for human approval before implementing.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "content": [
              {
                "text": "Three files to create:",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "- ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "agents/senior-dev/prompt.md",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "- ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "agents/senior-dev/README.md",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "- ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": ".github/workflows/senior-dev.yml",
                "type": "text"
              },
              {
                "text": " — modeled on ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": ".github/workflows/jira-ticket.yml",
                "type": "text"
              },
              {
                "text": "; triggered via ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "workflow_dispatch",
                "type": "text"
              },
              {
                "text": " and/or ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "repository_dispatch",
                "type": "text"
              },
              {
                "text": " from the orchestrator",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Context",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "text": "Handles the complex-ticket path in the agentic workflow (",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "docs/agentic-workflow.md",
                "type": "text"
              },
              {
                "text": "). The Development Orchestrator (KAN-1) routes here when a ticket is too complex for the Junior Dev agent. A human checkpoint between spec and implementation reduces wasted work on misunderstood requirements. Depends on KAN-1 being complete.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Implementation decisions (pick one each; document the choice in README)",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "marks": [
                  {
                    "type": "strong"
                  }
                ],
                "text": "Spec exploration approach:",
                "type": "text"
              },
              {
                "text": " ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "docs/agentic-workflow.md",
                "type": "text"
              },
              {
                "text": " references ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "/openspec:explore",
                "type": "text"
              },
              {
                "text": ". This is not a built-in Claude Code command and does not exist in ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": ".claude/skills/",
                "type": "text"
              },
              {
                "text": ". The implementer must either create a custom skill at ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": ".claude/skills/openspec/",
                "type": "text"
              },
              {
                "text": " or define an equivalent approach directly in the prompt. Verify what is actually available in ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "anthropics/claude-code-action@v1",
                "type": "text"
              },
              {
                "text": " before deciding.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "content": [
              {
                "marks": [
                  {
                    "type": "strong"
                  }
                ],
                "text": "Human-in-the-loop pause",
                "type": "text"
              },
              {
                "text": " (pick one):",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "- Write the spec to a draft PR and resume only when a human posts a magic-keyword comment (e.g. ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "!approve-spec",
                "type": "text"
              },
              {
                "text": ").",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "- Post the spec as a Jira comment and resume on a ticket transition or label.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Acceptance Criteria",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "content": [
                  {
                    "content": [
                      {
                        "text": "Dispatching the workflow on a complex KAN ticket produces a spec artifact and pauses execution.",
                        "type": "text"
                      }
                    ],
                    "type": "paragraph"
                  }
                ],
                "type": "listItem"
              },
              {
                "content": [
                  {
                    "content": [
                      {
                        "text": "A defined human approval action resumes the workflow into implementation.",
                        "type": "text"
                      }
                    ],
                    "type": "paragraph"
                  }
                ],
                "type": "listItem"
              },
              {
                "content": [
                  {
                    "content": [
                      {
                        "text": "Run log committed under ",
                        "type": "text"
                      },
                      {
                        "marks": [
                          {
                            "type": "code"
                          }
                        ],
                        "text": ".github/agent-logs/senior-dev/\u003cDATE\u003e/\u003cRUN_ID\u003e.json",
                        "type": "text"
                      },
                      {
                        "text": ".",
                        "type": "text"
                      }
                    ],
                    "type": "paragraph"
                  }
                ],
                "type": "listItem"
              }
            ],
            "type": "bulletList"
          }
        ],
        "type": "doc",
        "version": 1
